const inputData = $input.first().json; 
const texto_bruto = inputData.output || inputData.text || "";

const extraerTexto = (campo, fallback) => {
    const regex = new RegExp(`${campo}[:\\s]+([^\\n]+)`, 'i');
    const match = texto_bruto.match(regex);
    return match ? match[1].trim() : fallback;
};

// Agarra solo el PRIMER número de la lista para BigQuery
const extraerPrimerNumero = (campo, fallback) => {
    const texto = extraerTexto(campo, "");
    if (!texto) return fallback;
    const primerNumero = texto.split(',')[0].trim(); 
    return parseFloat(primerNumero.replace(',', '.')) || fallback;
};

const reporte_limpio = texto_bruto.replace(/\[MOSTRAR_GRAFICO\][\s\S]*/i, "").trim();

return [{
    json: {
        // --- DATOS PARA BIGQUERY (datos_sectoriales) ---
        timestamp: new Date().toISOString(),
        session_id: inputData.session_id || `aereo-${Date.now()}`,
        sector: "AEREO",

        // Mapeo adaptado a las columnas de tu BD (Ajustá los nombres si tu tabla Aereo es distinta)
        region: extraerTexto("aeropuerto_origen", "S/D") + " - " + extraerTexto("aeropuerto_destino", "S/D"),
        altitud_vuelo: extraerPrimerNumero("altitud_vuelo", 0),
        temperatura_altitud: extraerPrimerNumero("temperatura_altitud", 15),
        corrientes_viento: extraerPrimerNumero("corrientes_viento", 0),
        visibilidad_km: extraerPrimerNumero("visibilidad_km", 10),
        condiciones_atmosfericas: extraerTexto("condiciones_atmosfericas", "S/D"),

        ai_recommendations: reporte_limpio,
        metadata: JSON.stringify({ status: "success" }),

        // --- DATOS PARA DJANGO Y CHART.JS ---
        output: texto_bruto 
    }
}];
